const Skills: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let particles: Array<{
      x: number, 
      y: number, 
      vx: number, 
      vy: number, 
      size: number, 
      color: string, 
      pulse: number,
      opacity: number
    }> = [];

    const colors = ['#00f2ff', '#00d4ff', '#bc00ff', '#00ff9f'];

    const resizeCanvas = () => {
      const parent = canvas.parentElement;
      if (parent) {
        canvas.width = parent.clientWidth;
        canvas.height = parent.clientHeight;
      }
      initParticles();
    };

    const initParticles = () => {
      particles = [];
      const particleCount = 60;

      for (let i = 0; i < particleCount; i++) {
        particles.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          vx: (Math.random() - 0.5) * 0.4,
          vy: (Math.random() - 0.5) * 0.4,
          size: Math.random() * 2 + 1,
          color: colors[Math.floor(Math.random() * colors.length)],
          pulse: Math.random() * Math.PI * 2,
          opacity: Math.random() * 0.5 + 0.3
        });
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const connectionDistance = 120;
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const p1 = particles[i];
          const p2 = particles[j];
          const dx = p1.x - p2.x;
          const dy = p1.y - p2.y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < connectionDistance) {
            const opacity = (1 - dist / connectionDistance) * 0.25;
            ctx.beginPath();
            ctx.strokeStyle = p1.color;
            ctx.globalAlpha = opacity;
            ctx.lineWidth = 1;
            ctx.moveTo(p1.x, p1.y);
            ctx.lineTo(p2.x, p2.y);
            ctx.stroke();
          }
        }
      }

      particles.forEach((p) => {
        p.x += p.vx;
        p.y += p.vy;
        p.pulse += 0.03;

        if (p.x < 0 || p.x > canvas.width) p.vx *= -1;
        if (p.y < 0 || p.y > canvas.height) p.vy *= -1;

        const currentSize = p.size + Math.sin(p.pulse) * 0.6;

        ctx.save();
        ctx.globalAlpha = p.opacity;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, currentSize, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
    draw();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <section id="skills" className="py-24 md:py-40 bg-white/30 dark:bg-midnight/30 transition-colors duration-500 backdrop-blur-sm">
      <div className="max-w-[1440px] mx-auto px-4 sm:px-10 lg:px-16">
        <div className="text-center mb-24 md:mb-32">
          <h2 className="text-4xl font-bold text-slate-900 dark:text-white sm:text-6xl mb-8 leading-tight">Technical Ecosystem</h2>
          <p className="text-xl text-slate-600 dark:text-slate-300 max-w-4xl mx-auto">
            A comprehensive suite of certifications and tools honed through years of 
            global product delivery.
          </p>
        </div>

        {/* Certifications Section */}
        <div className="mb-24 md:mb-32">
          <h3 className="text-2xl font-black text-slate-900 dark:text-white mb-16 flex items-center justify-center gap-4 uppercase tracking-[0.2em]">
            <BadgeCheck className="h-9 w-9 text-blue-600 dark:text-blue-400" />
            Core Credentials
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
            {CERTIFICATIONS.map((cert, index) => (
              <div key={index} className="bg-white/80 dark:bg-slate-900/40 p-10 rounded-3xl shadow-sm border border-slate-100 dark:border-blue-500/20 hover:border-blue-400 dark:hover:border-blue-500 transition-all group hover:-translate-y-2 hover:shadow-2xl backdrop-blur-md">
                <div className={`w-24 h-24 mx-auto mb-8 group-hover:scale-110 transition-transform`}>
                  <img 
                    src={cert.logoUrl} 
                    alt={cert.issuer}
                    className="w-full h-full object-contain"
                  />
                </div>
                <h4 className="font-black text-slate-900 dark:text-white text-xl mb-3 leading-tight text-center">{cert.name}</h4>
                <p className="text-sm text-blue-600 dark:text-blue-400 font-black mb-6 text-center tracking-[0.15em] uppercase">{cert.issuer}</p>
                <p className="text-base text-slate-500 dark:text-slate-400 leading-relaxed text-center">
                  {cert.description}
                </p>
              </div>
            ))}
          </div>
