import React, { useState } from 'react';
import { CASE_STUDIES } from '../constants';
import { ArrowUpRight, BarChart3, CheckCircle2, Target } from 'lucide-react';
import { CaseStudy } from '../types';

const CaseStudies: React.FC = () => {
  const [activeId, setActiveId] = useState<string | null>(
    (CASE_STUDIES && CASE_STUDIES.length > 0) ? CASE_STUDIES[0].id : null
  );

  const activeStudy = CASE_STUDIES.find(c => c.id === activeId);

  const getChartData = (study: CaseStudy) => {
     if (!study || !study.metrics) return [];
     return study.metrics.map(m => {
        let val = 50; 
        const s = m.value;
        if (s.includes('%')) val = parseInt(s.replace(/\D/g, '')) || 0;
        else if (s.includes('$') || s.includes('M') || s.includes('k')) val = 95;
        else if (s.toLowerCase().includes('real-time')) val = 90;
        else val = 75;
        return { name: m.label, value: Math.max(30, Math.min(val, 100)), fullValue: m.value };
     });
  };

  const renderChart = (study: CaseStudy) => {
    const data = getChartData(study);
    return (
      <div className="flex-grow w-full flex items-end justify-between gap-3 pt-4 pb-1 px-1 select-none min-h-[140px]">
        {data.map((item, i) => (
          <div key={i} className="flex flex-col items-center justify-end w-1/2 h-full group relative">
            <div className="flex-grow w-full flex items-end justify-center mb-2">
                <div className="relative w-full max-w-[56px] h-full bg-slate-800/50 rounded-t-xl flex items-end overflow-hidden shadow-inner ring-1 ring-white/5">
                   <div style={{ height: `${item.value}%` }} className={`w-full transition-all duration-1000 ease-out ${i === 1 ? 'bg-blue-400' : 'bg-blue-600'}`}></div>
                </div>
            </div>
            <div className="h-10 w-full flex flex-col justify-start items-center text-center">
              <span className="block text-[8px] text-slate-400 uppercase tracking-widest font-extrabold w-full truncate">{item.name}</span>
              <span className="block font-black text-white text-sm">{item.fullValue}</span>
            </div>
          </div>
        ))}
      </div>
    );
  };

  return (
    <section id="work" className="py-16 md:py-24 bg-white/40 dark:bg-midnight/40 border-t border-slate-200 dark:border-blue-900/20 transition-colors duration-300 backdrop-blur-sm">
