          <h2 className="text-3xl font-bold text-slate-900 dark:text-white sm:text-5xl mb-6 leading-tight">Featured Case Studies</h2>
          <p className="text-lg text-slate-600 dark:text-slate-300 max-w-4xl leading-relaxed">
            Deep dives into my most impactful projects, structured by the STAR method.
          </p>
        </div>

        <div className="lg:grid lg:grid-cols-12 gap-10">
          <div className="lg:col-span-3 mb-8 lg:mb-0">
            <div className="space-y-4 lg:max-h-[600px] lg:overflow-y-auto lg:pr-2 custom-scrollbar">
              {CASE_STUDIES.map((study) => (
                <button
                  key={study.id}
                  onClick={() => setActiveId(study.id)}
                  className={`w-full text-left p-6 rounded-3xl border transition-all duration-300 backdrop-blur-md ${
                    activeId === study.id
                      ? 'bg-slate-900 dark:bg-blue-900/60 border-slate-900 dark:border-blue-400/50 shadow-xl'
                      : 'bg-white/80 dark:bg-slate-900/40 border-slate-200 dark:border-blue-900/20 hover:bg-slate-50'
                  }`}
                >
                  <h3 className={`text-lg font-bold mb-2 ${activeId === study.id ? 'text-white' : 'text-slate-900 dark:text-white'}`}>
                    {study.title}
                  </h3>
                  <p className={`text-xs line-clamp-2 ${activeId === study.id ? 'text-slate-300' : 'text-slate-600 dark:text-slate-400'}`}>
