                    <div>
                        <h3 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-white mb-2 tracking-tight">{activeStudy.title}</h3>
                        <p className="text-blue-600 dark:text-blue-400 font-black text-sm uppercase tracking-[0.2em]">{activeStudy.role}</p>
