                <div className="bg-slate-50 dark:bg-blue-900/20 px-8 py-6 border-b border-slate-200 dark:border-blue-900/30 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                    <div>
                        <h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{activeStudy.title}</h3>
                        <p className="text-blue-600 dark:text-blue-400 font-black text-[10px] uppercase tracking-[0.2em]">{activeStudy.role}</p>
                    </div>
                    <div className="flex gap-2">
                        {activeStudy.tags.slice(0, 3).map(tag => (
                            <span key={tag} className="px-3 py-1 bg-white dark:bg-blue-950 border border-slate-200 dark:border-blue-500/20 rounded-lg text-[9px] font-black text-slate-500 dark:text-blue-300 uppercase tracking-widest">
                                {tag}
                            </span>
                        ))}
                    </div>
                </div>

                <div className="p-8 space-y-8">
                    {/* Situation - Full Width Top */}
                    <div className="bg-blue-50/30 dark:bg-blue-900/10 p-6 rounded-2xl border border-blue-100/50 dark:border-blue-900/20">
                        <div className="flex items-center gap-2 mb-2 text-blue-800 dark:text-blue-300 font-black text-xs uppercase tracking-widest">
                            <Target className="h-4 w-4" />
                            Situation
                        </div>
                        <p className="text-slate-700 dark:text-slate-300 text-sm leading-relaxed">
                            {activeStudy.star.situation}
                        </p>
                    </div>

                    {/* Task, Action, Result - Grid Row */}
                    <div className="grid md:grid-cols-3 gap-6">
                        {/* Task */}
                        <div className="space-y-3">
                            <div className="flex items-center gap-2 text-rose-600 dark:text-rose-400 font-black text-xs uppercase tracking-widest">
                                <Zap className="h-4 w-4" />
                                Task
                            </div>
                            <p className="text-slate-700 dark:text-slate-300 text-sm leading-relaxed font-medium italic">
                                "{activeStudy.star.task}"
                            </p>
                        </div>

                        {/* Action */}
                        <div className="space-y-3">
                            <div className="flex items-center gap-2 text-blue-600 dark:text-blue-400 font-black text-xs uppercase tracking-widest">
                                <TrendingUp className="h-4 w-4" />
                                Action
                            </div>
                            <ul className="space-y-2">
                                {activeStudy.star.action.map((act, i) => (
                                    <li key={i} className="flex gap-2 text-xs text-slate-600 dark:text-slate-400 leading-snug">
                                        <div className="h-1 w-1 bg-blue-500 rounded-full mt-1.5 shrink-0" />
                                        {act}
                                    </li>
                                ))}
                            </ul>
                        </div>

                        {/* Result */}
                        <div className="space-y-3">
                            <div className="flex items-center gap-2 text-emerald-600 dark:text-emerald-400 font-black text-xs uppercase tracking-widest">
                                <CheckCircle2 className="h-4 w-4" />
                                Result
                            </div>
                            <ul className="space-y-2">
                                {activeStudy.star.result.map((res, i) => (
                                    <li key={i} className="flex gap-2 text-xs text-slate-900 dark:text-slate-100 font-bold leading-snug">
                                        <div className="h-1 w-1 bg-emerald-500 rounded-full mt-1.5 shrink-0" />
                                        {res}
                                    </li>
                                ))}
                            </ul>
                        </div>
                    </div>

                    {/* Metrics Footer */}
                    <div className="pt-6 border-t border-slate-100 dark:border-blue-900/20">
                        {renderChart(activeStudy)}
                    </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

export default CaseStudies;

